-- ----------------------------
-- View structure for dim_calendario_soc
-- ----------------------------
DROP VIEW IF EXISTS `dim_calendario_soc`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `dim_calendario_soc` AS select distinct cast(`tb_logs_soc_bruto`.`Data_Hora` as date) AS `Data`,year(`tb_logs_soc_bruto`.`Data_Hora`) AS `Ano`,month(`tb_logs_soc_bruto`.`Data_Hora`) AS `Mes_Num`,(case month(`tb_logs_soc_bruto`.`Data_Hora`) when 1 then 'Janeiro' when 2 then 'Fevereiro' when 3 then 'Março' when 4 then 'Abril' when 5 then 'Maio' when 6 then 'Junho' when 7 then 'Julho' when 8 then 'Agosto' when 9 then 'Setembro' when 10 then 'Outubro' when 11 then 'Novembro' when 12 then 'Dezembro' end) AS `Mes_Nome`,concat((case month(`tb_logs_soc_bruto`.`Data_Hora`) when 1 then 'Jan' when 2 then 'Fev' when 3 then 'Mar' when 4 then 'Abr' when 5 then 'Mai' when 6 then 'Jun' when 7 then 'Jul' when 8 then 'Ago' when 9 then 'Set' when 10 then 'Out' when 11 then 'Nov' when 12 then 'Dez' end),'/',year(`tb_logs_soc_bruto`.`Data_Hora`)) AS `Mes_Ano`,((year(`tb_logs_soc_bruto`.`Data_Hora`) * 100) + month(`tb_logs_soc_bruto`.`Data_Hora`)) AS `Mes_Ano_Index` from `tb_logs_soc_bruto`;

