DROP VIEW IF EXISTS `dim_servidores`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `dim_servidores` AS select distinct `tb_logs_soc_bruto`.`Servidor_Alvo` AS `Nome_Servidor`,(case when (`tb_logs_soc_bruto`.`Servidor_Alvo` like 'SRV-DB%') then 'Banco de Dados' when (`tb_logs_soc_bruto`.`Servidor_Alvo` like 'SRV-WEB%') then 'Servidor Web' else 'Infraestrutura de Rede' end) AS `Categoria_Ativo` from `tb_logs_soc_bruto`;

